class LmdbSketchJoinOptimizerAnchorTest {

	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void deduplicatesEquivalentFiniteLiteralAnchorsBeforePlanning() {
		BindingSetAssignment firstAnchor = values("optName", "user7", "user8");
		BindingSetAssignment duplicateAnchor = values("optName", "user7", "user8");
		StatementPattern nameLookup = new StatementPattern(new Var("e"),
				new Var("_const_name", VF.createIRI("urn:name")),
				new Var("optName"));
		QueryRoot root = new QueryRoot(new Join(firstAnchor, new Join(duplicateAnchor, nameLookup)));
		CapturingPlanner planner = new CapturingPlanner();

		new LmdbSketchJoinOptimizer(planner, false).optimize(root, null, null);

		assertEquals(1, planner.countCapturedAssignments("optName"));
	}

	private static BindingSetAssignment values(String bindingName, String... values) {
		BindingSetAssignment assignment = new BindingSetAssignment();
		assignment.setBindingNames(Set.of(bindingName));
		List<BindingSet> bindingSets = new ArrayList<>(values.length);
		for (String value : values) {
			MapBindingSet bindingSet = new MapBindingSet(1);
			bindingSet.addBinding(bindingName, VF.createLiteral(value));
			bindingSets.add(bindingSet);
		}
		assignment.setBindingSets(bindingSets);
		return assignment;
	}

	private static final class CapturingPlanner extends EvaluationStatistics implements JoinOrderPlanner {

		private List<TupleExpr> capturedArgs = List.of();

		@Override
		public Optional<JoinOrderPlan> planJoinOrder(List<TupleExpr> args, Set<String> initiallyBoundVars,
				Algorithm algorithm) {
			capturedArgs = List.copyOf(args);
			return Optional.of(new JoinOrderPlan(args, 1.0d, 1.0d));
		}

		private long countCapturedAssignments(String bindingName) {
			return capturedArgs.stream()
					.filter(BindingSetAssignment.class::isInstance)
					.map(BindingSetAssignment.class::cast)
					.filter(assignment -> assignment.getBindingNames().contains(bindingName))
					.count();
		}
	}
}
